## Protocols

Protocols define a blueprint of methods, properties, and requirements that can be adopted by classes, structs, or enums.

### Defining a Protocol

```swift
protocol Drawable {
    var color: String { get set }
    func draw()
}
```

### Conforming to a Protocol

```swift
struct Circle: Drawable {
    var color: String
    var radius: Double

    func draw() {
        print("Drawing a \(color) circle with radius \(radius)")
    }
}
```

### Protocol Extensions

Add default implementations:

```swift
protocol Printable {
    var description: String { get }
}

extension Printable {
    func printInfo() {
        print(description)
    }
}
```

sections.starterCode:
import Foundation

// Define protocols
protocol Animal {
    var name: String { get }
    func makeSound() -> String
}

protocol Prey {
    func flee()
}

protocol Predator {
    func hunt()
}

// Conforming to multiple protocols
struct Rabbit: Animal, Prey {
    let name: String

    func makeSound() -> String {
        return "*silence*"
    }

    func flee() {
        print("\(name) hops away!")
    }
}

struct Wolf: Animal, Predator {
    let name: String

    func makeSound() -> String {
        return "Woof!"
    }

    func hunt() {
        print("\(name) is hunting...")
    }
}

// Use protocols
func describeAnimal(_ animal: Animal) {
    print("\(animal.name) says: \(animal.makeSound())")
}

let rabbit = Rabbit(name: "Bugs")
let wolf = Wolf(name: "Wolfy")

describeAnimal(rabbit)
describeAnimal(wolf)
rabbit.flee()

