import Foundation

protocol Animal {
    var name: String { get }
    func makeSound() -> String
}

struct Rabbit: Animal, Prey {
    let name: String
    func makeSound() -> String { return "*silence*" }
    func flee() { print("\(name) hops away!") }
}

describeAnimal(Rabbit(name: "Bugs"))
